import React, { useEffect, useMemo, useState } from "react";
import { useLocation, useNavigate } from "react-router-dom";

const Header = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const [menuOpen, setMenuOpen] = useState(false);

  const parseTokenPayload = () => {
    const token = localStorage.getItem("accessToken");
    if (!token) return null;

    try {
      const payload = JSON.parse(atob(token.split(".")[1]));
      return payload;
    } catch (error) {
      console.error("토큰 파싱 실패:", error);
      return null;
    }
  };

  const payload = useMemo(() => parseTokenPayload(), [location.pathname]);
  const isLoggedIn = !!localStorage.getItem("accessToken");
  const role = payload?.role || null;
  const nickname = payload?.nickname || payload?.name || "메이트 사용자";
  const isAdmin = role === "ADMIN" || role === "SUPERADMIN";

  useEffect(() => {
    document.body.classList.toggle("menu-open", menuOpen);
    return () => document.body.classList.remove("menu-open");
  }, [menuOpen]);

  useEffect(() => {
    setMenuOpen(false);
  }, [location.pathname]);

  const moveToSection = (sectionId) => {
    setMenuOpen(false);

    if (location.pathname !== "/") {
      navigate(`/#${sectionId}`);
      setTimeout(() => {
        const target = document.getElementById(sectionId);
        if (target) target.scrollIntoView({ behavior: "smooth", block: "start" });
      }, 120);
      return;
    }

    const target = document.getElementById(sectionId);
    if (target) {
      target.scrollIntoView({ behavior: "smooth", block: "start" });
    }
  };

  const moveToPage = (path) => {
    setMenuOpen(false);
    navigate(path);
  };

  const handleLogout = () => {
    localStorage.removeItem("accessToken");
    localStorage.removeItem("refreshToken");
    setMenuOpen(false);
    navigate("/");
    window.location.reload();
  };

  const guestMenus = [
    { label: "소개", action: () => moveToSection("intro") },
    { label: "가격", action: () => moveToSection("pricing") },
    { label: "도움말", action: () => moveToSection("help") },
    { label: "무료 체험", action: () => moveToPage("/signup"), highlight: true },
    { label: "다운로드", action: () => moveToPage("/download") },
  ];

  const userMenus = [
    { label: "소개", action: () => moveToSection("intro") },
    { label: "가격", action: () => moveToSection("pricing") },
    { label: "도움말", action: () => moveToSection("help") },
    { label: "다운로드", action: () => moveToPage("/download") },
    { label: "대시보드", action: () => moveToPage("/dashboard") },
    { label: "마이페이지", action: () => moveToPage("/mypage") },
    ...(isAdmin
      ? [{ label: "관리자페이지", action: () => moveToPage("/admin") }]
      : []),
  ];

  const desktopMenus = isLoggedIn ? userMenus : guestMenus;

  return (
    <header className="matey-header">
      <div className="matey-header__inner">
        <div className="matey-header__left">
          <div className="matey-logo" onClick={() => moveToPage("/")} role="button" tabIndex={0}>
            <div className="matey-logo__symbol">M</div>
            <div className="matey-logo__text">
              <strong>메이티</strong>
              <span>먼저 다가오는 AI 메이트</span>
            </div>
          </div>
        </div>

        <nav className="matey-nav" aria-label="메인 메뉴">
          {desktopMenus.map((menu) => (
            <button
              key={menu.label}
              type="button"
              className={`matey-nav__link ${menu.highlight ? "is-highlight" : ""}`}
              onClick={menu.action}
            >
              {menu.label}
            </button>
          ))}
        </nav>

        <div className="matey-header__actions">
          {!isLoggedIn ? (
            <>
              <button
                type="button"
                className="matey-header__text-btn"
                onClick={() => moveToPage("/login")}
              >
                로그인
              </button>

              <button
                type="button"
                className="matey-header__solid-btn"
                onClick={() => moveToPage("/signup")}
              >
                회원가입
              </button>
            </>
          ) : (
            <>
              <div className="matey-user-badge">
                {isAdmin ? "👑 관리자" : "🌷"} {nickname}
              </div>

              <button
                type="button"
                className="matey-header__outline-btn"
                onClick={handleLogout}
              >
                로그아웃
              </button>
            </>
          )}

          <button
            type="button"
            className="matey-mobile-menu-btn"
            aria-label="모바일 메뉴 열기"
            onClick={() => setMenuOpen((prev) => !prev)}
          >
            <span />
            <span />
            <span />
          </button>
        </div>
      </div>

      {menuOpen && (
        <div className="matey-mobile-drawer">
          <div className="matey-mobile-drawer__group">
            {(isLoggedIn ? userMenus : guestMenus).map((menu) => (
              <button key={menu.label} type="button" onClick={menu.action}>
                {menu.label}
              </button>
            ))}
          </div>

          <div className="matey-mobile-drawer__group">
            {!isLoggedIn ? (
              <>
                <button type="button" onClick={() => moveToPage("/login")}>
                  로그인
                </button>
                <button type="button" onClick={() => moveToPage("/signup")}>
                  회원가입
                </button>
              </>
            ) : (
              <>
                <button type="button" onClick={() => moveToPage("/mypage")}>
                  마이페이지
                </button>
                <button type="button" onClick={handleLogout}>
                  로그아웃
                </button>
              </>
            )}
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;
